+import {Options, RuleType} from '../rules';
+import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {
+  level: number,
+  text: string,
+  anchor: string,
+};
+
+const startMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const endMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^ {0,3}(#{1,6})(?:[ \	]+(.*)|[ \	]*)$/;
+
+function removeImagesAndResolveLinks(value: string): string {
+  return value
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+      .replace(/\\[\\[([^\\]]+)\\]\\]/g, '$1')
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(value: string): string {
+  let result = value;
+  // Repeat to handle nested emphasis, such as **_text_**.
+  for (let i = 0; i < 3; i++) {
+    result = result
+        .replace(/(\\*\\*|__)(.*?)\\1/g, '$2')
+        .replace(/(\\*|_)(.*?)\\1/g, '$2')
+        .replace(/~~(.*?)~~/g, '$1');
+  }
+
+  return result.replace(/`([^`]*)`/g, '$1');
+}
+
+function headingText(value: string): {text: string, explicitId?: string} {
+  const withoutClosingHashes = value.replace(/[ \	]+#+[ \	]*$/, '').trim();
+  const explicitId = withoutClosingHashes.match(/\\s*\\{#([^\\s}]+)\\}\\s*$/);
+  return {
+    text: (explicitId ? withoutClosingHashes.slice(0, explicitId.index) : withoutClosingHashes).trim(),
+    explicitId: explicitId?.[1],
+  };
+}
+
+function toAnchor(value: string): string {
+  return stripFormatting(removeImagesAndResolveLinks(value))
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(value: string, exclusions: string[]): boolean {
+  return exclusions.some((exclusion) => {
+    const regex = exclusion.match(/^\\/(.*)\\/$/);
+    if (regex) {
+      try {
+        return new RegExp(regex[1], 'i').test(value);
+      } catch (_) {
+        // Invalid regular expressions are treated as literal exclusions.
+      }
+    }
+    return exclusion.toLowerCase() === value.toLowerCase();
+  });
+}
+
+function getHeadings(lines: string[], tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+  const headings: Heading[] = [];
+  const anchorCounts = new Map<string, number>();
+  let inYaml = false;
+  let inCodeFence: {character: string, length: number} = null;
+  let inMath = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    if (index === 0 && /^---\\s*$/.test(line)) {
+      inYaml = true;
+      continue;
+    }
+    if (inYaml) {
+      if (/^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+      continue;
+    }
+
+    const fence = line.match(/^ {0,3}(`{3,}|~{3,})/);
+    if (fence) {
+      if (!inCodeFence) {
+        inCodeFence = {character: fence[1][0], length: fence[1].length};
+        continue;
+      }
+      if (fence[1][0] === inCodeFence.character && fence[1].length >= inCodeFence.length) {
+        inCodeFence = null;
+      }
+      continue;
+    }
+    if (inCodeFence) continue;
+
+    if (/^ {0,3}\\$\\$\\s*$/.test(line)) {
+      inMath = !inMath;
+      continue;
+    }
+    if (inMath || (index >= tocStart && index <= tocEnd)) continue;
+
+    const match = line.match(atxHeading);
+    if (!match) continue;
+    const level = match[1].length;
+    if (level < options.minLevel || level > options.maxLevel) continue;
+
+    const parsed = headingText(match[2] ?? '');
+    const displayText = removeImagesAndResolveLinks(parsed.text);
+    const comparableText = stripFormatting(displayText);
+    if (isExcluded(comparableText, options.excludeHeadings)) continue;
+
+    const baseAnchor = options.useExplicitIds && parsed.explicitId ? parsed.explicitId : toAnchor(parsed.text);
+    const previousCount = anchorCounts.get(baseAnchor) ?? 0;
+    anchorCounts.set(baseAnchor, previousCount + 1);
+    const anchor = previousCount === 0 ? baseAnchor : `${baseAnchor}-${previousCount}`;
+    headings.push({
+      level,
+      text: options.stripFormattingInToc ? comparableText : displayText,
+      anchor,
+    });
+  }
+  return headings;
+}
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lineEnding = text.includes('\\r\
') ? '\\r\
' : '\
';
+    const lines = text.split(/\\r?\
/);
+    const tocStart = lines.findIndex((line) => startMarker.test(line));
+    if (tocStart === -1) return text;
+
+    const foundEnd = lines.slice(tocStart + 1).findIndex((line) => endMarker.test(line));
+    const tocEnd = foundEnd === -1 ? tocStart : tocStart + foundEnd + 1;
+    const headings = getHeadings(lines, tocStart, tocEnd, options);
+    const tocLines = headings.map((heading, index) => {
+      const indentation = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+      const marker = options.listStyle === 'number'
+        ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.`
+        : options.bulletMarker;
+      return `${indentation}${marker} [${heading.text}](#${heading.anchor})`;
+    });
+
