+    if (options.title) replacement.push(options.title, '');
+    replacement.push(...tocLines);
+    if (tocLines.length > 0) replacement.push('');
+    replacement.push('<!-- /toc -->', '');
+
+    const suffix = lines.slice(tocEnd + 1);
+    while (suffix.length > 0 && /^\\s*$/.test(suffix[0])) suffix.shift();
+    return [...lines.slice(0, tocStart), ...replacement, ...suffix].join(lineEnding);
+  }
